function ytThumb(id) {
  return `https://img.youtube.com/vi/${id}/hqdefault.jpg`;
}

function extractYtId(url) {
  const m = url?.match(/(?:v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
  return m ? m[1] : null;
}

function posColor(p) {
  if (p <= 150)  return "#e11d48";
  if (p <= 400)  return "#ea580c";
  if (p <= 750)  return "#ca8a04";
  if (p <= 1200) return "#16a34a";
  return "#6b7280";
}

function enjoColor(v) {
  const val = Number(v) || 0;
  if (val >= 82) return "#2f7df6";
  if (val >= 68) return "#10b981";
  if (val >= 50) return "#f59e0b";
  if (val > 0)   return "#ef4444";
  return "#9ca3af";
}

function EnjoBadge({ v, size = 12 }) {
  const val = Number(v) || 0;
  if (!val) return <span style={{ color: "#9ca3af", fontSize: size }}>N/A</span>;
  return <span style={{ color: enjoColor(val), fontWeight: 800, fontSize: size }}>{val.toFixed(1)}</span>;
}

function PosBadge({ pos }) {
  const col = posColor(pos);
  return (
    <span style={{
      background: col + "18", color: col,
      border: "1px solid " + col + "35",
      borderRadius: 6, padding: "2px 7px",
      fontSize: 11, fontWeight: 800, fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap"
    }}>
      #{pos}
    </span>
  );
}

