export default function AdminPanel() {
  const [tab, setTab]         = useState("records");
  const [overrides, setOv]    = useState({});
  const [custom, setCu]       = useState([]);
  const [loaded, setLoaded]   = useState(false);
  const [editId, setEditId]   = useState(null);
  const [editForm, setEF]     = useState({});
  const [editCustomUid, setECU] = useState(null);
  const [editCustomForm, setECF] = useState({});
  const [search, setSearch]   = useState("");
  const [addTarget, setAT]    = useState(null);
  const [addForm, setAF]      = useState({});
  const [toast, setToast]     = useState(null);
  const toastRef = useRef(null);

  useEffect(() => {
    (async () => {
      try { const r = await window.storage.get(SK_OV); if (r) setOv(JSON.parse(r.value)); } catch {}
      try { const r = await window.storage.get(SK_CU); if (r) setCu(JSON.parse(r.value)); } catch {}
      setLoaded(true);
    })();
  }, []);

  function showToast(msg, ok = true) {
    setToast({ msg, ok });
    clearTimeout(toastRef.current);
    toastRef.current = setTimeout(() => setToast(null), 2800);
  }

  // ——— Overrides (MY_RECORDS) ———
  function startEdit(levelId) {
    const ov  = overrides[String(levelId)] || {};
    const rank = RIDX[levelId];
    setEF({ image: ov.image || "", enjoyment: ov.enjoyment ?? rank?.e ?? 50, notes: ov.notes || "" });
    setEditId(String(levelId));
  }
  async function saveEdit(levelId) {
    const next = { ...overrides, [String(levelId)]: editForm };
    try { await window.storage.set(SK_OV, JSON.stringify(next)); setOv(next); setEditId(null); showToast("Sauvegardé ✓"); }
    catch { showToast("Erreur ✕", false); }
  }

  // ——— Custom levels ———
  function startEditCustom(item) {
    setECF({ name: item.name, position: item.position, points: item.points, image: item.image || "", videoUrl: item.videoUrl || "", enjoyment: item.enjoyment ?? 50, notes: item.notes || "" });
    setECU(item.uid);
  }
  async function saveEditCustom(uid) {
    const next = custom.map(c => c.uid === uid ? { ...c, ...editCustomForm } : c);
    try { await window.storage.set(SK_CU, JSON.stringify(next)); setCu(next); setECU(null); showToast("Sauvegardé ✓"); }
    catch { showToast("Erreur ✕", false); }
  }
  async function deleteCustom(uid) {
    const next = custom.filter(c => c.uid !== uid);
    try { await window.storage.set(SK_CU, JSON.stringify(next)); setCu(next); showToast("Supprimé"); }
    catch {}
  }
  async function saveNewCustom() {
    if (!addForm.name) return;
    const next = [...custom, { ...addForm, uid: Date.now().toString() }];
    try { await window.storage.set(SK_CU, JSON.stringify(next)); setCu(next); setAT(null); setSearch(""); setTab("records"); showToast("Niveau ajouté ✓"); }
    catch { showToast("Erreur ✕", false); }
  }

  const searchResults = search.length >= 2
    ? RANKS.filter(r => r.n.toLowerCase().includes(search.toLowerCase())).slice(0, 30)
    : [];

  const allRecords = [
    ...MY_RECORDS.map(r => ({ ...r, isCustom: false })),
    ...custom.map(c => ({ levelId: c.levelId || 0, name: c.name, position: c.position, points: c.points, ytId: extractYtId(c.videoUrl), twoP: false, isCustom: true, uid: c.uid }))
  ].sort((a, b) => a.position - b.position);

  if (!loaded) return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "100vh", fontFamily: "Inter, sans-serif", color: "#5c6b84", gap: 10 }}>
      <div style={{ width: 20, height: 20, border: "3px solid #d9e7ff", borderTop: "3px solid #2f7df6", borderRadius: "50%", animation: "spin 1s linear infinite" }} />
      Chargement…
      <style>{"@keyframes spin{to{transform:rotate(360deg)}}"}</style>
    </div>
  );

  return (
    <div style={S.root}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        *{box-sizing:border-box;margin:0}
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        @keyframes slideIn{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
        input:focus,textarea:focus{border-color:#2f7df6!important;box-shadow:0 0 0 3px rgba(47,125,246,.14)!important;outline:none}
        input[type=range]{accent-color:#2f7df6}
        .card:hover{box-shadow:0 6px 28px rgba(47,125,246,.14)!important}
        button:hover{opacity:.88}
        textarea{resize:vertical}
        .res-row:hover{background:#f8fbff!important}
      `}</style>

      {/* ── HEADER ── */}
      <div style={S.hdr}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 900, letterSpacing: "-.03em", display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: 20 }}>⚙️</span>
            <span>Panel Admin</span>
            <span style={{ color: "#2f7df6", fontWeight: 800 }}>Spleen</span>
          </div>
          <div style={{ fontSize: 12, color: "#5c6b84", marginTop: 3 }}>
            {MY_RECORDS.length} records AREDL · {custom.length} perso · {Object.keys(overrides).length} modifié(s)
          </div>
        </div>
        <div style={{ display: "flex", gap: 7, flexWrap: "wrap" }}>
          {[["Rang", "#3806", "#2f7df6"], ["Clan", "Iris", "#7c3aed"], ["Extremes", "17", "#ea580c"]].map(([lbl, val, col]) => (
            <span key={lbl} style={{ background: col + "14", color: col, border: "1px solid " + col + "30", borderRadius: 8, padding: "4px 10px", fontSize: 12, fontWeight: 700 }}>
              {lbl}: {val}
            </span>
          ))}
        </div>
      </div>

      {/* ── TABS ── */}
      <div style={S.tabBar}>
        <button style={S.tab(tab === "records")} onClick={() => { setTab("records"); setAT(null); setSearch(""); }}>
          📋 Complétions ({allRecords.length})
        </button>
        <button style={S.tab(tab === "add")} onClick={() => setTab("add")}>
          ➕ Ajouter un niveau
        </button>
      </div>

      {/* ══════════════════════════════════
          TAB: RECORDS
      ══════════════════════════════════ */}
      {tab === "records" && (
        <div style={S.grid}>
          {allRecords.map(rec => {
            const lvlKey   = String(rec.levelId);
            const ov       = overrides[lvlKey] || {};
            const rank     = RIDX[rec.levelId];
            const cuItem   = rec.isCustom ? custom.find(c => c.uid === rec.uid) : null;
            const isEditing = !rec.isCustom && editId === lvlKey;
            const isCuEdit  = rec.isCustom && editCustomUid === rec.uid;

            const imgSrc = ov.image || cuItem?.image || (rec.ytId ? ytThumb(rec.ytId) : null);
            const myEnjo = ov.enjoyment ?? cuItem?.enjoyment ?? null;
            const commEnjo = rank?.e ?? 0;

            return (
              <div key={rec.isCustom ? rec.uid : rec.levelId} className="card" style={{ ...S.card, animation: "fadeUp .3s ease" }}>

                {/* ── Card top ── */}
                <div style={{ display: "flex", gap: 10, padding: 14 }}>
                  {/* Thumbnail */}
                  <div style={{ position: "relative", flexShrink: 0 }}>
                    {imgSrc ? (
                      <img
                        src={imgSrc} alt={rec.name} style={S.thumb}
                        onError={e => { e.target.onerror = null; e.target.src = ""; e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
                      />
                    ) : null}
                    <div style={{ ...S.thumb, display: imgSrc ? "none" : "flex", alignItems: "center", justifyContent: "center", background: "linear-gradient(135deg,#dcebff,#e8f0fe)", fontSize: 10, fontWeight: 700, color: "#5c6b84", textAlign: "center", padding: 4 }}>
                      {rec.name.slice(0, 8)}
                    </div>
                    {rec.isCustom && (
                      <span style={{ position: "absolute", top: -5, left: -5, background: "#7c3aed", color: "white", fontSize: 9, fontWeight: 800, borderRadius: 5, padding: "1px 5px" }}>PERSO</span>
                    )}
                    {rec.twoP && (
                      <span style={{ position: "absolute", bottom: -5, right: -5, background: "#0891b2", color: "white", fontSize: 9, fontWeight: 800, borderRadius: 5, padding: "1px 5px" }}>2P</span>
                    )}
                  </div>

                  {/* Info */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 6, flexWrap: "wrap", marginBottom: 5 }}>
                      <PosBadge pos={rec.position} />
                      <span style={{ fontWeight: 800, fontSize: 13, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{rec.name}</span>
                    </div>
                    <div style={{ fontSize: 12, color: "#5c6b84", display: "flex", gap: 10, flexWrap: "wrap" }}>
                      <span style={{ fontWeight: 700 }}>⭐ {rec.points} pts</span>
                      {commEnjo > 0 && (
                        <span>Comm: <EnjoBadge v={commEnjo} /></span>
                      )}
                    </div>
                    {myEnjo !== null && (
                      <div style={{ fontSize: 11, color: "#5c6b84", marginTop: 3 }}>
                        Ma note: <EnjoBadge v={myEnjo} />
                      </div>
                    )}
                    {(ov.notes || cuItem?.notes) && !isEditing && !isCuEdit && (
                      <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 4, fontStyle: "italic", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                        💬 {ov.notes || cuItem?.notes}
                      </div>
                    )}
                  </div>
                </div>

                {/* ── Edit form – MY_RECORDS ── */}
                {isEditing && (
                  <div style={{ borderTop: "1px solid #f0f6ff", padding: 14, background: "#f8fbff" }}>
                    <Label>Image URL</Label>
                    <div style={{ display: "flex", gap: 6, marginBottom: 4 }}>
                      <input style={S.inp} placeholder="https://..." value={editForm.image}
                        onChange={e => setEF(f => ({ ...f, image: e.target.value }))} />
                      {rec.ytId && (
                        <button style={S.btn("#64748b")} onClick={() => setEF(f => ({ ...f, image: ytThumb(rec.ytId) }))}>YT</button>
                      )}
                    </div>
                    {editForm.image && (
                      <img src={editForm.image} alt="preview" style={{ height: 48, borderRadius: 6, objectFit: "cover", marginBottom: 10 }} onError={e => e.target.style.display = "none"} />
                    )}

                    <Label extra={<EnjoBadge v={editForm.enjoyment} />}>Enjoyment perso</Label>
                    <input type="range" min="0" max="100" step="0.5" style={{ width: "100%", marginBottom: 10 }}
                      value={editForm.enjoyment} onChange={e => setEF(f => ({ ...f, enjoyment: +e.target.value }))} />

                    <Label>Notes</Label>
                    <textarea style={{ ...S.inp, minHeight: 56, marginBottom: 12 }} placeholder="Impressions, tips…"
                      value={editForm.notes} onChange={e => setEF(f => ({ ...f, notes: e.target.value }))} />

                    <div style={{ display: "flex", gap: 8 }}>
                      <button style={S.btn("#2f7df6")} onClick={() => saveEdit(rec.levelId)}>✓ Sauvegarder</button>
                      <button style={S.gBtn} onClick={() => setEditId(null)}>Annuler</button>
                    </div>
                  </div>
                )}

                {/* ── Edit form – Custom level ── */}
                {isCuEdit && (
                  <div style={{ borderTop: "1px solid #f0f6ff", padding: 14, background: "#f8fbff" }}>
                    <Label>Nom</Label>
                    <input style={{ ...S.inp, marginBottom: 10 }} value={editCustomForm.name}
                      onChange={e => setECF(f => ({ ...f, name: e.target.value }))} />

                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 10 }}>
                      <div><Label>Position</Label>
                        <input type="number" style={S.inp} value={editCustomForm.position}
                          onChange={e => setECF(f => ({ ...f, position: +e.target.value }))} /></div>
                      <div><Label>Points</Label>
                        <input type="number" style={S.inp} value={editCustomForm.points}
                          onChange={e => setECF(f => ({ ...f, points: +e.target.value }))} /></div>
                    </div>

                    <Label>Image URL</Label>
                    <div style={{ display: "flex", gap: 6, marginBottom: 4 }}>
                      <input style={S.inp} placeholder="https://..." value={editCustomForm.image}
                        onChange={e => setECF(f => ({ ...f, image: e.target.value }))} />
                    </div>

                    <Label>URL Vidéo YouTube</Label>
                    <input style={{ ...S.inp, marginBottom: 10 }} placeholder="https://youtube.com/watch?v=..."
                      value={editCustomForm.videoUrl}
                      onChange={e => {
                        const vid = e.target.value;
                        const id = extractYtId(vid);
                        setECF(f => ({ ...f, videoUrl: vid, image: f.image || (id ? ytThumb(id) : "") }));
                      }} />

                    <Label extra={<EnjoBadge v={editCustomForm.enjoyment} />}>Enjoyment perso</Label>
                    <input type="range" min="0" max="100" step="0.5" style={{ width: "100%", marginBottom: 10 }}
                      value={editCustomForm.enjoyment} onChange={e => setECF(f => ({ ...f, enjoyment: +e.target.value }))} />

                    <Label>Notes</Label>
                    <textarea style={{ ...S.inp, minHeight: 56, marginBottom: 12 }} placeholder="Impressions…"
                      value={editCustomForm.notes} onChange={e => setECF(f => ({ ...f, notes: e.target.value }))} />

                    <div style={{ display: "flex", gap: 8 }}>
                      <button style={S.btn("#2f7df6")} onClick={() => saveEditCustom(rec.uid)}>✓ Sauvegarder</button>
                      <button style={S.gBtn} onClick={() => setECU(null)}>Annuler</button>
                    </div>
                  </div>
                )}

                {/* ── Card footer actions ── */}
                {!isEditing && !isCuEdit && (
                  <div style={{ padding: "0 14px 12px", display: "flex", justifyContent: "flex-end", gap: 6 }}>
                    {rec.isCustom ? (
                      <>
                        <button style={S.gBtn} onClick={() => startEditCustom(cuItem)}>✏️ Modifier</button>
                        <button style={S.btn("#ef4444")} onClick={() => deleteCustom(rec.uid)}>🗑</button>
                      </>
                    ) : (
                      <button style={S.gBtn} onClick={() => startEdit(rec.levelId)}>✏️ Modifier</button>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* ══════════════════════════════════
          TAB: ADD LEVEL
      ══════════════════════════════════ */}
      {tab === "add" && !addTarget && (
        <>
          <div style={{ background: "white", border: "1px solid #d9e7ff", borderRadius: 16, padding: 16, marginBottom: 12, boxShadow: "0 2px 12px rgba(47,125,246,.07)" }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: "#5c6b84", marginBottom: 8 }}>
              Rechercher parmi {RANKS.length} niveaux AREDL
            </div>
            <input style={S.inp} autoFocus placeholder="Bloodbath, Sakupen, Tartarus…" value={search} onChange={e => setSearch(e.target.value)} />
          </div>

          {search.length >= 2 ? (
            <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
              {searchResults.length === 0 ? (
                <div style={{ textAlign: "center", padding: 30, color: "#94a3b8", fontSize: 14 }}>
                  Aucun résultat pour « {search} »
                </div>
              ) : searchResults.map(rank => {
                const already = MY_RECORDS.some(r => r.levelId === rank.id) || custom.some(c => c.levelId === rank.id);
                return (
                  <div key={rank.id} className="res-row" style={{ background: "white", border: "1px solid #d9e7ff", borderRadius: 12, padding: "10px 14px", display: "flex", alignItems: "center", gap: 10, boxShadow: "0 1px 6px rgba(47,125,246,.05)", opacity: already ? .5 : 1 }}>
                    <PosBadge pos={rank.p} />
                    <span style={{ flex: 1, fontWeight: 700, fontSize: 13, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{rank.n}</span>
                    <span style={{ fontSize: 12, color: "#5c6b84", whiteSpace: "nowrap" }}>{rank.pts} pts</span>
                    <span style={{ fontSize: 12, whiteSpace: "nowrap" }}><EnjoBadge v={rank.e} /></span>
                    <button
                      style={S.btn(already ? "#94a3b8" : "#2f7df6")}
                      disabled={already}
                      onClick={() => {
                        setAT(rank);
                        setAF({ name: rank.n, position: rank.p, points: rank.pts, levelId: rank.id, image: "", videoUrl: "", enjoyment: rank.e || 50, notes: "" });
                      }}
                    >
                      {already ? "Déjà ajouté" : "+ Ajouter"}
                    </button>
                  </div>
                );
              })}
            </div>
          ) : (
            <div style={{ background: "white", border: "1px dashed #d9e7ff", borderRadius: 16, padding: 48, textAlign: "center", color: "#94a3b8" }}>
              <div style={{ fontSize: 36, marginBottom: 10 }}>🎮</div>
              <div style={{ fontWeight: 700, fontSize: 15, color: "#5c6b84" }}>Ajouter un niveau non terminé</div>
              <div style={{ fontSize: 13, marginTop: 6 }}>Tu peux tracker des niveaux en cours ou planifiés</div>
            </div>
          )}
        </>
      )}

      {/* ── Add Form ── */}
      {tab === "add" && addTarget && (
        <div style={{ background: "white", border: "1px solid #d9e7ff", borderRadius: 16, padding: 20, boxShadow: "0 4px 24px rgba(47,125,246,.1)", animation: "fadeUp .25s ease" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 18 }}>
            <div>
              <div style={{ fontWeight: 900, fontSize: 18, letterSpacing: "-.02em" }}>{addTarget.n}</div>
              <div style={{ color: "#5c6b84", fontSize: 13, marginTop: 3, display: "flex", gap: 8 }}>
                <PosBadge pos={addTarget.p} />
                <span>{addTarget.pts} pts</span>
                <span>Comm: <EnjoBadge v={addTarget.e} /></span>
              </div>
            </div>
            <button style={S.gBtn} onClick={() => setAT(null)}>← Retour</button>
          </div>

          <Label>URL Vidéo YouTube (ta completion)</Label>
          <input style={{ ...S.inp, marginBottom: 10 }} placeholder="https://www.youtube.com/watch?v=..."
            value={addForm.videoUrl}
            onChange={e => {
              const vid = e.target.value;
              const id = extractYtId(vid);
              setAF(f => ({ ...f, videoUrl: vid, image: f.image || (id ? ytThumb(id) : "") }));
            }} />

          <Label>Image URL</Label>
          <div style={{ display: "flex", gap: 6, marginBottom: 4 }}>
            <input style={S.inp} placeholder="Auto-rempli depuis YouTube…"
              value={addForm.image} onChange={e => setAF(f => ({ ...f, image: e.target.value }))} />
          </div>
          {addForm.image && (
            <img src={addForm.image} alt="preview" style={{ height: 56, borderRadius: 8, objectFit: "cover", marginBottom: 10 }} onError={e => e.target.style.display = "none"} />
          )}

          <Label extra={<EnjoBadge v={addForm.enjoyment} />}>Ma note d'enjoyment</Label>
          <div style={{ position: "relative", marginBottom: 4 }}>
            <input type="range" min="0" max="100" step="0.5" style={{ width: "100%" }}
              value={addForm.enjoyment} onChange={e => setAF(f => ({ ...f, enjoyment: +e.target.value }))} />
          </div>
          <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 10 }}>
            Note communautaire AREDL: <EnjoBadge v={addTarget.e} size={11} />
          </div>

          <Label>Notes perso (optionnel)</Label>
          <textarea style={{ ...S.inp, minHeight: 70, marginBottom: 16 }} placeholder="Impressions, % atteint, difficultés…"
            value={addForm.notes} onChange={e => setAF(f => ({ ...f, notes: e.target.value }))} />

          <div style={{ display: "flex", gap: 8 }}>
            <button style={S.btn("#2f7df6")} onClick={saveNewCustom}>✓ Ajouter à ma liste</button>
            <button style={S.gBtn} onClick={() => setAT(null)}>Annuler</button>
          </div>
        </div>
      )}

      {/* ── Toast ── */}
      {toast && (
        <div style={{ position: "fixed", bottom: 20, right: 20, background: toast.ok ? "#2f7df6" : "#ef4444", color: "white", borderRadius: 12, padding: "10px 18px", fontWeight: 700, fontSize: 13, boxShadow: "0 4px 20px rgba(0,0,0,.2)", zIndex: 999, animation: "slideIn .3s ease" }}>
          {toast.msg}
        </div>
      )}
    </div>
  );
}

function Label({ children, extra }) {
  return (
    <div style={{ fontSize: 11, fontWeight: 700, color: "#5c6b84", display: "flex", justifyContent: "space-between", marginBottom: 4, marginTop: 8 }}>
      <span>{children}</span>
      {extra}
    </div>
  );
}
